import{_ as a,o as e,c as o,a2 as l}from"./chunks/framework.Pywvta2k.js";const g=JSON.parse('{"title":"邓铁涛","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/05-近现代/07-邓铁涛.md","filePath":"tcm-data/05-近现代/07-邓铁涛.md","lastUpdated":1781084559000}'),r={name:"tcm-data/05-近现代/07-邓铁涛.md"};function n(s,t,i,d,h,c){return e(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="邓铁涛" tabindex="-1">邓铁涛 <a class="header-anchor" href="#邓铁涛" aria-label="Permalink to &quot;邓铁涛&quot;">​</a></h1><blockquote><p>邓铁涛（1916-2019年），广东开平人 国医大师，中医现代化的推动者 代表作：《邓铁涛医学文集》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：名锡，字铁涛</li><li><strong>生平</strong>：11岁开始学医，1937年毕业于广东中医药专门学校</li><li><strong>经历</strong>：广州中医药大学终身教授，首届国医大师</li><li><strong>学术地位</strong>：<strong>现代中医教育的奠基人之一</strong>，&quot;岭南医学&quot;的代表人物</li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-五脏相关学说" tabindex="-1">1. 五脏相关学说 <a class="header-anchor" href="#_1-五脏相关学说" aria-label="Permalink to &quot;1. 五脏相关学说&quot;">​</a></h3><blockquote><p><strong>「五脏相关，非五行生克所能尽。」</strong></p></blockquote><p>邓铁涛认为：五行学说过于机械，五脏之间的关系统一称为&quot;<strong>五脏相关</strong>&quot;更符合临床实际。</p><h3 id="_2-脾胃学说临床发挥" tabindex="-1">2. 脾胃学说临床发挥 <a class="header-anchor" href="#_2-脾胃学说临床发挥" aria-label="Permalink to &quot;2. 脾胃学说临床发挥&quot;">​</a></h3><p>邓铁涛特别重视脾胃，继承李东垣的补土思想，认为：</p><blockquote><p><strong>「脾胃为后天之本，百病皆由脾胃衰而生。」</strong></p></blockquote><h3 id="_3-重症肌无力的治疗" tabindex="-1">3. 重症肌无力的治疗 <a class="header-anchor" href="#_3-重症肌无力的治疗" aria-label="Permalink to &quot;3. 重症肌无力的治疗&quot;">​</a></h3><p>邓铁涛在<strong>重症肌无力</strong>领域有极高造诣，以补中益气汤为主方，疗效显著。</p><h3 id="_4-冠心病治疗-——-益气除痰" tabindex="-1">4. 冠心病治疗 —— 益气除痰 <a class="header-anchor" href="#_4-冠心病治疗-——-益气除痰" aria-label="Permalink to &quot;4. 冠心病治疗 —— 益气除痰&quot;">​</a></h3><blockquote><p><strong>「冠心病，气阴两虚为本，痰瘀阻络为标。」</strong></p></blockquote><p>治疗以益气养阴、化痰通络为主，代表方：温胆汤加减。</p><h3 id="_5-中医现代化" tabindex="-1">5. 中医现代化 <a class="header-anchor" href="#_5-中医现代化" aria-label="Permalink to &quot;5. 中医现代化&quot;">​</a></h3><p>邓铁涛终身致力于中医现代化，提出：</p><blockquote><p><strong>「中医不能西化，但必须现代化。」</strong></p></blockquote><p>他推动了中医进入现代高等教育体系。</p><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>强肌健力饮</strong></td><td style="text-align:left;">黄芪、五爪龙、党参、白术、当归、升麻、柴胡、甘草、陈皮</td><td style="text-align:left;">重症肌无力</td></tr><tr><td style="text-align:left;"><strong>冠心三号方</strong></td><td style="text-align:left;">党参、白术、茯苓、甘草、法半夏、竹茹、枳实、橘红</td><td style="text-align:left;">冠心病</td></tr><tr><td style="text-align:left;"><strong>软肝煎</strong></td><td style="text-align:left;">太子参、白术、茯苓、甘草、鳖甲、土鳖虫、丹参、黄芪</td><td style="text-align:left;">肝硬化</td></tr></tbody></table><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><blockquote><p><strong>「五脏相关，非五行生克所能尽。」</strong></p></blockquote><blockquote><p><strong>「中医不能西化，但必须现代化。」</strong></p></blockquote><blockquote><p><strong>「中医的希望在疗效，疗效的根基在经典。」</strong></p></blockquote><blockquote><p><strong>「岭南医学，以养阴为主，兼祛湿热。」</strong></p></blockquote><blockquote><p><strong>「一个中医，如果没有经典功底，就谈不上辨证论治。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><ul><li>推动了中医进入国家高等教育体系</li><li>&quot;五脏相关&quot;学说为中医现代化提供了新视角</li><li>重症肌无力的治疗经验至今是中医的标杆</li></ul><hr><p><em>本条目为精简框架版。可扩展至邓铁涛五脏相关学说详解、岭南医学专题等。</em></p>',37)])])}const q=a(r,[["render",n]]);export{g as __pageData,q as default};
